import React, { useState, useRef, useEffect, useMemo } from 'react';
import Fuse from 'fuse.js';
import { motion, AnimatePresence } from 'framer-motion';
import {
  MessageSquare,
  Search,
  History,
  Mic,
  Square,
  Play,
  Sparkles,
  Trash2,
  Calendar,
  ChevronRight,
  Wind,
  BarChart3,
  X,
  LayoutDashboard,
  LogOut,
  ArrowLeft,
  User
} from 'lucide-react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  AreaChart,
  Area
} from 'recharts';
import './index.css';

const API_BASE_URL = 'http://localhost:5000';

function App() {
  // Autenticação e Perfis
  const [usuario, setUsuario] = useState(() => {
    const saved = localStorage.getItem('usuario');
    return saved ? JSON.parse(saved) : null;
  });

  const [authMode, setAuthMode] = useState('login'); // 'login' or 'cadastro'
  const [authTipo, setAuthTipo] = useState('paciente'); // 'paciente' or 'psicologo'
  const [authNome, setAuthNome] = useState('');
  const [authEmail, setAuthEmail] = useState('');
  const [authSenha, setAuthSenha] = useState('');
  const [authPsicologoId, setAuthPsicologoId] = useState('');
  const [listaPsicologos, setListaPsicologos] = useState([]);

  // Estados do Chat e Histórico (Paciente)
  const [gravando, setGravando] = useState(false);
  const [transcricao, setTranscricao] = useState('');
  const [exercicio, setExercicio] = useState('');
  const [carregando, setCarregando] = useState(false);
  const [historico, setHistorico] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [sessaoAtiva, setSessaoAtiva] = useState(null);
  const [currentView, setCurrentView] = useState('app'); // 'app' or 'dashboard'
  const [showSOS, setShowSOS] = useState(false);
  const [breathingStep, setBreathingStep] = useState('Inspire');
  const [falando, setFalando] = useState(false);

  // Estados do Psicólogo
  const [listaPacientes, setListaPacientes] = useState([]);
  const [pacienteSelecionado, setPacienteSelecionado] = useState(null);

  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);
  const audioContextRef = useRef(null);

  // Carregar psicólogos para a tela de cadastro de pacientes
  useEffect(() => {
    if (authMode === 'cadastro' && authTipo === 'paciente') {
      fetch(`${API_BASE_URL}/psicologos`)
        .then(res => res.json())
        .then(data => {
          setListaPsicologos(data);
          if (data.length > 0) setAuthPsicologoId(data[0].id);
        })
        .catch(err => console.error("Erro ao buscar psicólogos:", err));
    }
  }, [authMode, authTipo]);

  // Carregar histórico ao iniciar (se for paciente logado)
  useEffect(() => {
    if (usuario && usuario.tipo === 'paciente') {
      fetchHistorico();
    } else if (usuario && usuario.tipo === 'psicologo') {
      fetchPacientes();
    }
  }, [usuario]);

  // Carregar histórico do paciente selecionado (se for psicólogo)
  useEffect(() => {
    if (usuario && usuario.tipo === 'psicologo' && pacienteSelecionado) {
      fetchHistorico(pacienteSelecionado.id);
    } else {
      setHistorico([]);
    }
    setSessaoAtiva(null);
    setTranscricao('');
    setExercicio('');
  }, [pacienteSelecionado]);

  const fetchHistorico = async (pacienteId = null) => {
    if (!usuario) return;
    try {
      let url = `${API_BASE_URL}/historico`;
      if (usuario.tipo === 'psicologo' && pacienteId) {
        url += `?paciente_id=${pacienteId}`;
      }

      const resp = await fetch(url, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setHistorico(data.map(item => ({
        ...item,
        sentimento: item.sentimento || 'Neutro'
      })));
    } catch (err) {
      console.error("Erro ao carregar histórico:", err);
    }
  };

  const fetchPacientes = async () => {
    if (!usuario || usuario.tipo !== 'psicologo') return;
    try {
      const resp = await fetch(`${API_BASE_URL}/pacientes`, {
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      const data = await resp.json();
      setListaPacientes(data);
    } catch (err) {
      console.error("Erro ao carregar pacientes:", err);
    }
  };

  // Autenticação handlers
  const handleLogin = async (e) => {
    e.preventDefault();
    if (!authEmail || !authSenha) return;
    setCarregando(true);
    try {
      const resp = await fetch(`${API_BASE_URL}/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: authEmail, senha: authSenha })
      });
      const data = await resp.json();
      if (resp.ok) {
        setUsuario(data);
        localStorage.setItem('usuario', JSON.stringify(data));
        setAuthEmail('');
        setAuthSenha('');
      } else {
        alert(data.erro || "Erro ao realizar login");
      }
    } catch (err) {
      console.error("Erro no login:", err);
      alert("Erro na conexão com o servidor.");
    } finally {
      setCarregando(false);
    }
  };

  const handleCadastro = async (e) => {
    e.preventDefault();
    if (!authNome || !authEmail || !authSenha) return;
    setCarregando(true);
    try {
      const payload = {
        nome: authNome,
        email: authEmail,
        senha: authSenha,
        tipo: authTipo
      };
      if (authTipo === 'paciente' && authPsicologoId) {
        payload.psicologo_id = Number(authPsicologoId);
      }

      const resp = await fetch(`${API_BASE_URL}/cadastro`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      const data = await resp.json();
      if (resp.ok) {
        alert("Cadastro realizado com sucesso! Faça login para continuar.");
        setAuthMode('login');
        setAuthNome('');
      } else {
        alert(data.erro || "Erro ao realizar cadastro");
      }
    } catch (err) {
      console.error("Erro no cadastro:", err);
      alert("Erro na conexão com o servidor.");
    } finally {
      setCarregando(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('usuario');
    setUsuario(null);
    setHistorico([]);
    setListaPacientes([]);
    setPacienteSelecionado(null);
    setSessaoAtiva(null);
    setTranscricao('');
    setExercicio('');
    setCurrentView('app');
    window.speechSynthesis.cancel();
    setFalando(false);
  };

  // Lógica da animação de respiração e Som de Baixa Frequência (Guadalupe/432Hz)
  useEffect(() => {
    if (!showSOS) {
      if (audioContextRef.current) {
        audioContextRef.current.close().catch(() => { });
        audioContextRef.current = null;
      }
      return;
    }

    const AudioContext = window.AudioContext || window.webkitAudioContext;
    const ctx = new AudioContext();
    audioContextRef.current = ctx;

    const masterGain = ctx.createGain();
    masterGain.gain.setValueAtTime(0, ctx.currentTime);
    masterGain.gain.linearRampToValueAtTime(0.12, ctx.currentTime + 2);
    masterGain.connect(ctx.destination);

    const osc1 = ctx.createOscillator();
    osc1.type = 'sine';
    osc1.frequency.setValueAtTime(432, ctx.currentTime);

    const osc2 = ctx.createOscillator();
    osc2.type = 'sine';
    osc2.frequency.setValueAtTime(433.5, ctx.currentTime);

    osc1.connect(masterGain);
    osc2.connect(masterGain);

    osc1.start();
    osc2.start();

    const steps = ['Inspire', 'Segure', 'Expire', 'Segure'];
    let idx = 0;
    const interval = setInterval(() => {
      idx = (idx + 1) % steps.length;
      setBreathingStep(steps[idx]);
    }, 4000);

    return () => {
      clearInterval(interval);
      if (ctx.state !== 'closed') {
        masterGain.gain.linearRampToValueAtTime(0, ctx.currentTime + 1);
        setTimeout(() => ctx.close().catch(() => { }), 1100);
      }
    };
  }, [showSOS]);

  // Prepara as vozes do sistema
  useEffect(() => {
    const carregarVozes = () => window.speechSynthesis.getVoices();
    carregarVozes();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = carregarVozes;
    }
  }, []);

  const falar = (texto) => {
    if (!texto || !('speechSynthesis' in window)) return;

    window.speechSynthesis.cancel();
    window.speechSynthesis.resume();

    const mensagemPura = texto
      .replace(/SENTIMENTO:.*?\n/g, '')
      .replace(/ABORDAGEM:/g, 'Abordagem teórica sugerida: ')
      .replace(/LAUDO:/g, 'Laudo de acompanhamento: ')
      .replace(/MAPA:/g, 'Mapa de sensibilidade: ')
      .replace(/ORIENTACAO:/g, 'Orientação técnica: ')
      .replace(/SESSAO:/g, 'Pauta para a próxima sessão: ')
      .replace(/[*#=_\-]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();

    const chunks = mensagemPura.match(/.{1,200}(?:\s|$)/g) || [mensagemPura];
    let currentChunk = 0;

    const speakNextChunk = () => {
      if (currentChunk >= chunks.length) {
        setFalando(false);
        return;
      }

      const locutor = new SpeechSynthesisUtterance(chunks[currentChunk]);
      const vozes = window.speechSynthesis.getVoices();

      const vozCalma = vozes.find(v => v.name.includes('Natural') && v.lang.includes('pt-BR')) ||
        vozes.find(v => v.name.includes('Neural') && v.lang.includes('pt-BR')) ||
        vozes.find(v => v.name.includes('Google') && v.lang.includes('pt-BR')) ||
        vozes.find(v => v.lang.includes('pt-BR'));

      if (vozCalma) locutor.voice = vozCalma;
      locutor.lang = 'pt-BR';
      locutor.rate = 1.0;
      locutor.pitch = 0.75;
      locutor.volume = 0.9;

      locutor.onstart = () => {
        setFalando(true);
      };

      locutor.onend = () => {
        currentChunk++;
        setTimeout(speakNextChunk, 500);
      };

      locutor.onerror = () => setFalando(false);
      window.speechSynthesis.speak(locutor);
    };

    speakNextChunk();
  };

  const pararDeFalar = () => {
    window.speechSynthesis.cancel();
    setFalando(false);
  };

  const chartData = useMemo(() => {
    return historico.slice().reverse().map(item => ({
      data: item.data.split(' ')[0],
      sentimento: item.sentimento,
      valor: item.sentimento === 'Feliz' ? 3 : item.sentimento === 'Neutro' ? 2 : 1
    }));
  }, [historico]);

  const stats = useMemo(() => {
    return {
      total: historico.length,
      hoje: historico.filter(i => i.data.startsWith(new Date().toLocaleDateString('pt-BR'))).length,
      dominante: historico.length > 0 ? Object.entries(historico.reduce((acc, curr) => {
        acc[curr.sentimento] = (acc[curr.sentimento] || 0) + 1;
        return acc;
      }, {})).sort((a, b) => b[1] - a[1])[0][0] : 'Nenhum'
    };
  }, [historico]);

  const SOSOverlay = () => (
    <motion.div className="sos-overlay" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
      <button className="close-sos" onClick={() => setShowSOS(false)}><X size={24} /></button>
      <div className="breathing-container">
        <motion.div className="breathing-circle" animate={{ scale: breathingStep === 'Inspire' || breathingStep === 'Segure' ? 1.5 : 1 }} transition={{ duration: 4, ease: "easeInOut" }}>
          <Wind size={64} className="breathe-icon" />
        </motion.div>
        <h2 className="breathing-text">{breathingStep}</h2>
        <p style={{ opacity: 0.6 }}>Respire fundo, isso vai passar.</p>
      </div>
    </motion.div>
  );

  const DashboardView = () => (
    <div className="dashboard-view">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <h2><LayoutDashboard style={{ marginRight: 12, verticalAlign: 'middle' }} /> Painel de Evolução</h2>
        <button className="reset-btn" onClick={() => setCurrentView('app')}>Voltar ao Chat</button>
      </div>
      <div className="stats-grid">
        <div className="stat-card"><span className="stat-value">{stats.total}</span><span className="stat-label">Registros</span></div>
        <div className="stat-card"><span className="stat-value">{stats.hoje}</span><span className="stat-label">Hoje</span></div>
        <div className="stat-card"><span className="stat-value" style={{ fontSize: '1.1rem' }}>{stats.dominante}</span><span className="stat-label">Humor Dominante</span></div>
      </div>
      <div className="chart-container">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={chartData}>
            <defs>
              <linearGradient id="colorVal" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#8b5cf6" stopOpacity={0.3} />
                <stop offset="95%" stopColor="#8b5cf6" stopOpacity={0} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" strokeOpacity={0.05} vertical={false} />
            <XAxis dataKey="data" stroke="#64748b" fontSize={10} tickLine={false} />
            <YAxis hide />
            <Tooltip contentStyle={{ background: '#1e293b', border: 'none', borderRadius: '8px', fontSize: '12px' }} />
            <Area type="monotone" dataKey="valor" stroke="#8b5cf6" fillOpacity={1} fill="url(#colorVal)" strokeWidth={2} />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );

  const deleteSessao = async (e, id) => {
    e.stopPropagation();
    if (!window.confirm("Deseja apagar este registro do histórico?")) return;

    try {
      const resp = await fetch(`${API_BASE_URL}/sessao/${id}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${usuario.token}`
        }
      });

      if (resp.status === 401) {
        handleLogout();
        return;
      }

      fetchHistorico(pacienteSelecionado ? pacienteSelecionado.id : null);
      if (sessaoAtiva?.id === id) {
        setTranscricao('');
        setExercicio('');
        setSessaoAtiva(null);
      }
    } catch (err) {
      console.error("Erro ao deletar:", err);
    }
  };

  const getSentimentClass = (sentimento) => {
    const s = sentimento.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
    return `sentiment-${s}`;
  };

  const filteredHistorico = useMemo(() => {
    if (!searchTerm) return historico;
    const fuse = new Fuse(historico, {
      keys: ['transcricao', 'exercicio', 'sentimento'],
      threshold: 0.4
    });
    return fuse.search(searchTerm).map(result => result.item);
  }, [historico, searchTerm]);

  const iniciarGravacao = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new window.MediaRecorder(stream);
      audioChunksRef.current = [];
      mediaRecorderRef.current = mediaRecorder;

      mediaRecorder.ondataavailable = (e) => audioChunksRef.current.push(e.data);

      mediaRecorder.onstop = async () => {
        setCarregando(true);
        const audioBlob = new Blob(audioChunksRef.current);
        const formData = new FormData();
        formData.append('audio', audioBlob, 'sessao.mp3');

        try {
          const resposta = await fetch(`${API_BASE_URL}/transcribe`, {
            method: 'POST',
            headers: {
              'Authorization': `Bearer ${usuario.token}`
            },
            body: formData
          });

          if (resposta.status === 401) {
            handleLogout();
            return;
          }

          const dados = await resposta.json();
          setTranscricao(dados.transcricao);

          const respostaExercicio = await fetch(`${API_BASE_URL}/sugerir-exercicio`, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${usuario.token}`
            },
            body: JSON.stringify({
              transcricao: dados.transcricao,
              contexto_anterior: exercicio
            })
          });

          if (respostaExercicio.status === 401) {
            handleLogout();
            return;
          }

          const exercicioData = await respostaExercicio.json();
          setExercicio(exercicioData.exercicio);

          falar(exercicioData.exercicio);
          fetchHistorico();
        } catch (error) {
          console.error("Erro ao processar áudio:", error);
          setTranscricao("Erro na conexão com o assistente.");
        } finally {
          setCarregando(false);
        }
      };

      mediaRecorder.start();
      setGravando(true);
      if (!exercicio) {
        setTranscricao('');
      }
      setSessaoAtiva(null);
      window.speechSynthesis.cancel();
    } catch (err) {
      console.error("Erro ao acessar microfone:", err);
      alert("Por favor, permita o acesso ao microfone.");
    }
  };

  const pararGravacao = () => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
      setGravando(false);
      mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
    }
  };

  const selecionarSessao = (sessao) => {
    setSessaoAtiva(sessao);
    setTranscricao(sessao.transcricao);
    setExercicio(sessao.exercicio);
    falar(sessao.exercicio);
  };

  const formatarAnalise = (texto) => {
    if (!texto) return null;

    const getMatch = (tag) => {
      const regex = new RegExp(`${tag}:([\\s\\S]*?)(?=[A-Z]{4,}:|$)`);
      const match = texto.match(regex);
      return match ? match[1].trim() : null;
    };

    const sections = {
      abordagem: getMatch('ABORDAGEM'),
      laudo: getMatch('LAUDO'),
      mapa: getMatch('MAPA'),
      orientacao: getMatch('ORIENTACAO'),
      sessao: getMatch('SESSAO')
    };

    return (
      <div className="professional-analysis">
        {sections.abordagem && (
          <div className="analysis-section theory-badge">
            <h4 style={{ color: '#ec4899' }}><Sparkles size={14} style={{ marginRight: 8 }} /> Base Teórica</h4>
            <p className="theory-text"><strong>{sections.abordagem}</strong></p>
          </div>
        )}
        {sections.laudo && (
          <div className="analysis-section">
            <h4><ChevronRight size={14} /> Laudo de Acompanhamento</h4>
            <p className="clinical-text">{sections.laudo}</p>
          </div>
        )}

        {sections.mapa && (
          <div className="analysis-section sensitivity-map">
            <h4><ChevronRight size={14} /> Mapa de Sensibilidade</h4>
            <div className="trigger-cloud">
              {sections.mapa.split('\n').map((line, i) => line.trim() && (
                <span key={i} className="trigger-tag">{line.replace(/^[-*]\s*/, '')}</span>
              ))}
            </div>
          </div>
        )}

        {sections.orientacao && (
          <div className="analysis-section orientation">
            <h4><ChevronRight size={14} /> Orientação Técnica</h4>
            <p>{sections.orientacao}</p>
          </div>
        )}

        {sections.sessao && (
          <div className="analysis-section preparation">
            <h4><ChevronRight size={14} /> Pauta para Próxima Sessão</h4>
            <ul>
              {sections.sessao.split('\n').map((line, i) => line.trim() && (
                <li key={i}>{line.replace(/^[-*]\s*/, '')}</li>
              ))}
            </ul>
          </div>
        )}
      </div>
    );
  };

  const copiarParaPsicologo = () => {
    if (!exercicio) return;

    const getMatch = (tag) => {
      const regex = new RegExp(`${tag}:([\\s\\S]*?)(?=[A-Z]{4,}:|$)`);
      const match = exercicio.match(regex);
      return match ? match[1].trim() : null;
    };

    const laudo = getMatch('LAUDO');
    const mapa = getMatch('MAPA');
    const pauta = getMatch('SESSAO');

    const resumo = `
RESUMO CLÍNICO - PSICÓLOGO IA
==============================
DATA: ${sessaoAtiva?.data || new Date().toLocaleString()}

1. MEU DESABAFO:
"${transcricao}"

2. LAUDO DE ACOMPANHAMENTO:
${laudo}

3. MAPA DE SENSIBILIDADE (GATILHOS):
${mapa}

4. PAUTA PARA A PRÓXIMA SESSÃO:
${pauta}

------------------------------
Gerado por Psicólogo IA
    `;
    navigator.clipboard.writeText(resumo);
    alert("Resumo clínico copiado para transferência!");
  };

  // VISTA 1: Tela de Autenticação (Não Logado)
  if (!usuario) {
    return (
      <div className="auth-wrapper">
        <div className="auth-card">
          <div className="auth-header">
            <h2>Psicólogo IA</h2>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>
              {authMode === 'login' ? 'Entre na sua conta clínica' : 'Crie sua conta clínica'}
            </p>
          </div>

          <div className="auth-tabs">
            <button
              className={`auth-tab ${authTipo === 'paciente' ? 'active' : ''}`}
              onClick={() => setAuthTipo('paciente')}
            >
              Paciente
            </button>
            <button
              className={`auth-tab ${authTipo === 'psicologo' ? 'active' : ''}`}
              onClick={() => setAuthTipo('psicologo')}
            >
              Psicólogo
            </button>
          </div>

          <form className="auth-form" onSubmit={authMode === 'login' ? handleLogin : handleCadastro}>
            {authMode === 'cadastro' && (
              <div className="form-group">
                <label>Nome Completo</label>
                <input
                  type="text"
                  placeholder="Seu nome"
                  value={authNome}
                  onChange={(e) => setAuthNome(e.target.value)}
                  required
                />
              </div>
            )}

            <div className="form-group">
              <label>E-mail</label>
              <input
                type="email"
                placeholder="seuemail@exemplo.com"
                value={authEmail}
                onChange={(e) => setAuthEmail(e.target.value)}
                required
              />
            </div>

            <div className="form-group">
              <label>Senha</label>
              <input
                type="password"
                placeholder="Sua senha"
                value={authSenha}
                onChange={(e) => setAuthSenha(e.target.value)}
                required
              />
            </div>

            {authMode === 'cadastro' && authTipo === 'paciente' && (
              <div className="form-group">
                <label>Selecione o Psicólogo</label>
                <select
                  value={authPsicologoId}
                  onChange={(e) => setAuthPsicologoId(e.target.value)}
                  required
                >
                  {listaPsicologos.length === 0 && (
                    <option value="">Nenhum psicólogo cadastrado</option>
                  )}
                  {listaPsicologos.map((p) => (
                    <option key={p.id} value={p.id}>
                      {p.nome} ({p.email})
                    </option>
                  ))}
                </select>
              </div>
            )}

            <button type="submit" className="auth-submit-btn" disabled={carregando}>
              {carregando ? 'Aguarde...' : authMode === 'login' ? 'Entrar' : 'Cadastrar'}
            </button>
          </form>

          <div className="auth-switch-prompt">
            {authMode === 'login' ? (
              <>
                Não tem uma conta?
                <button className="auth-switch-link" onClick={() => setAuthMode('cadastro')}>
                  Cadastre-se
                </button>
              </>
            ) : (
              <>
                Já tem uma conta?
                <button className="auth-switch-link" onClick={() => setAuthMode('login')}>
                  Faça login
                </button>
              </>
            )}
          </div>
        </div>
      </div>
    );
  }

  // VISTA 2: Visão do Psicólogo (Gerenciamento de Pacientes)
  if (usuario.tipo === 'psicologo') {
    return (
      <div className="app-wrapper">
        <aside className="sidebar">
          <div className="user-profile-header">
            <div className="user-info">
              <span className="user-name">{usuario.nome}</span>
              <span className="user-role">Profissional</span>
            </div>
            <button className="logout-btn" onClick={handleLogout}>
              <LogOut size={14} />
            </button>
          </div>

          <div className="sidebar-header" style={{ padding: '1.5rem' }}>
            <h2 style={{ fontSize: '1.2rem', margin: 0 }}>
              <History size={18} style={{ marginRight: 8 }} /> Pacientes
            </h2>
          </div>

          <div className="history-list">
            {listaPacientes.map((p) => (
              <motion.div
                key={p.id}
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                className={`history-item ${pacienteSelecionado?.id === p.id ? 'active' : ''}`}
                onClick={() => setPacienteSelecionado(p)}
              >
                <div className="history-item-content">
                  <div style={{ fontWeight: '600', fontSize: '0.95rem', marginBottom: '4px' }}>
                    {p.nome}
                  </div>
                  <div className="preview" style={{ fontSize: '0.75rem', opacity: 0.7 }}>
                    Atividade: {p.ultima_atividade}
                  </div>
                </div>
              </motion.div>
            ))}
            {listaPacientes.length === 0 && (
              <div className="status-text" style={{ textAlign: 'center', marginTop: '2rem' }}>
                Nenhum paciente cadastrado
              </div>
            )}
          </div>
        </aside>

        <main className="main-content">
          <div className="app-container" style={{ maxWidth: '900px' }}>
            {!pacienteSelecionado ? (
              <div style={{ textAlign: 'center', marginTop: '4rem' }}>
                <User size={64} style={{ color: 'var(--accent)', opacity: 0.5, marginBottom: '1.5rem' }} />
                <h2 style={{ fontSize: '2rem', fontFamily: 'Outfit, sans-serif', marginBottom: '0.5rem' }}>
                  Bem-vindo, Dr(a). {usuario.nome.split(' ')[0]}!
                </h2>
                <p style={{ color: 'var(--text-muted)' }}>
                  Selecione um paciente na barra lateral para analisar o histórico evolutivo gerado pela IA.
                </p>
              </div>
            ) : (
              <div>
                <div className="patient-detail-header">
                  <div className="patient-detail-info">
                    <h2>{pacienteSelecionado.nome}</h2>
                    <p style={{ color: 'var(--text-muted)' }}>{pacienteSelecionado.email}</p>
                  </div>
                  <button className="back-link" onClick={() => setPacienteSelecionado(null)}>
                    <ArrowLeft size={16} /> Voltar para Pacientes
                  </button>
                </div>

                <div style={{ display: 'flex', gap: '12px', marginBottom: '2rem' }}>
                  <button
                    className={`nav-btn ${currentView === 'app' ? 'active' : ''}`}
                    onClick={() => setCurrentView('app')}
                    style={{ flex: 1, justifyContent: 'center', marginBottom: 0 }}
                  >
                    <MessageSquare size={16} style={{ marginRight: 8 }} /> Histórico Clínico
                  </button>
                  <button
                    className={`nav-btn ${currentView === 'dashboard' ? 'active' : ''}`}
                    onClick={() => setCurrentView('dashboard')}
                    style={{ flex: 1, justifyContent: 'center', marginBottom: 0 }}
                  >
                    <BarChart3 size={16} style={{ marginRight: 8 }} /> Dashboard de Evolução
                  </button>
                </div>

                {currentView === 'dashboard' ? (
                  <DashboardView />
                ) : (
                  <div style={{ display: 'flex', gap: '2rem' }}>
                    <div style={{ width: '30%', display: 'flex', flexDirection: 'column', gap: '12px' }}>
                      <div className="search-container" style={{ marginTop: 0 }}>
                        <Search className="search-icon" size={16} />
                        <input
                          type="text"
                          placeholder="Buscar registros..."
                          value={searchTerm}
                          onChange={(e) => setSearchTerm(e.target.value)}
                          style={{ padding: '0.6rem 0.8rem 0.6rem 2.2rem', fontSize: '0.85rem' }}
                        />
                      </div>
                      <div style={{ maxHeight: '500px', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        {filteredHistorico.map((item) => (
                          <div
                            key={item.id}
                            className={`history-item ${sessaoAtiva?.id === item.id ? 'active' : ''}`}
                            onClick={() => selecionarSessao(item)}
                            style={{ padding: '0.8rem' }}
                          >
                            <div className="date" style={{ fontSize: '0.65rem' }}>
                              {item.data}
                            </div>
                            <div className="preview" style={{ fontSize: '0.8rem' }}>{item.transcricao}</div>
                          </div>
                        ))}
                        {filteredHistorico.length === 0 && (
                          <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textAlign: 'center', marginTop: '1rem' }}>
                            Nenhum desabafo
                          </div>
                        )}
                      </div>
                    </div>

                    <div style={{ flex: 1 }}>
                      {exercicio ? (
                        <motion.div
                          className="result-card professional-card"
                          initial={{ opacity: 0, y: 10 }}
                          animate={{ opacity: 1, y: 0 }}
                          style={{ margin: 0, background: 'rgba(15, 23, 42, 0.4)' }}
                        >
                          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                            <h3 style={{ margin: 0, fontSize: '0.85rem', display: 'flex', alignItems: 'center' }}>
                              <Sparkles size={14} style={{ marginRight: 8 }} /> Ficha Evolutiva (IA)
                            </h3>
                            <div style={{ display: 'flex', gap: '8px' }}>
                              <button
                                onClick={falando ? pararDeFalar : () => falar(exercicio)}
                                className="audio-control-btn"
                                title={falando ? "Parar áudio" : "Ouvir laudo"}
                              >
                                {falando ? <Square size={14} fill="currentColor" /> : <Play size={14} fill="currentColor" />}
                              </button>
                              <button className="logout-btn" style={{ borderColor: 'rgba(239, 68, 68, 0.2)' }} onClick={(e) => deleteSessao(e, sessaoAtiva.id)}>
                                <Trash2 size={12} /> Apagar
                              </button>
                            </div>
                          </div>
                          <div className="result-card" style={{ background: 'rgba(0,0,0,0.2)', borderLeftColor: 'rgba(255,255,255,0.1)', padding: '1rem', marginBottom: '1.5rem' }}>
                            <h4 style={{ fontSize: '0.75rem', color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: '6px' }}>Relato do Paciente</h4>
                            <p style={{ fontSize: '0.95rem', color: '#e2e8f0', fontStyle: 'italic' }}>"{transcricao}"</p>
                          </div>
                          {formatarAnalise(exercicio)}
                        </motion.div>
                      ) : (
                        <div style={{ textAlign: 'center', padding: '4rem 2rem', background: 'rgba(255,255,255,0.02)', borderRadius: '1.5rem', border: '1px solid var(--glass-border)' }}>
                          <MessageSquare size={32} style={{ color: 'var(--accent)', opacity: 0.4, marginBottom: '1rem' }} />
                          <h4 style={{ margin: 0, color: 'var(--text-main)' }}>Selecione um desabafo na coluna esquerda</h4>
                          <p style={{ color: 'var(--text-muted)', fontSize: '0.85rem', marginTop: '0.5rem' }}>
                            Você poderá verificar a transcrição do áudio, gatilhos identificados e orientações teóricas da IA.
                          </p>
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </main>
      </div>
    );
  }

  // VISTA 3: Visão do Paciente (Chat, Gravação e Histórico)
  return (
    <div className="app-wrapper">
      <aside className="sidebar">
        <div className="user-profile-header">
          <div className="user-info">
            <span className="user-name">{usuario.nome}</span>
            <span className="user-role">Paciente</span>
          </div>
          <button className="logout-btn" onClick={handleLogout}>
            <LogOut size={14} />
          </button>
        </div>

        <div className="sidebar-header">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
            <h2 style={{ margin: 0 }}><History size={20} style={{ marginRight: 8 }} /> Histórico</h2>
            <button className="sos-btn-small" onClick={() => setShowSOS(true)} title="Modo SOS / Respiração">
              <Wind size={18} />
            </button>
          </div>
          <button
            className={`nav-btn ${currentView === 'dashboard' ? 'active' : ''}`}
            onClick={() => setCurrentView('dashboard')}
          >
            <BarChart3 size={18} style={{ marginRight: 8 }} /> Ver Evolução
          </button>
          <div className="search-container">
            <Search className="search-icon" size={18} />
            <input
              type="text"
              placeholder="Pesquisar registros..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="history-list">
          {filteredHistorico.map((item) => (
            <motion.div
              key={item.id}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              className={`history-item ${sessaoAtiva?.id === item.id ? 'active' : ''}`}
              onClick={() => selecionarSessao(item)}
            >
              <div className="history-item-content">
                <div className="date">
                  {item.data} • <span className={`sentiment-tag ${getSentimentClass(item.sentimento)}`}>{item.sentimento}</span>
                  <button className="delete-btn" onClick={(e) => deleteSessao(e, item.id)}>
                    <Trash2 size={14} />
                  </button>
                </div>
                <div className="preview">{item.transcricao}</div>
              </div>
            </motion.div>
          ))}
          {filteredHistorico.length === 0 && (
            <div className="status-text" style={{ textAlign: 'center', marginTop: '2rem' }}>
              Nenhum registro encontrado
            </div>
          )}
        </div>
      </aside>

      <main className="main-content">
        <AnimatePresence>
          {showSOS && <SOSOverlay />}
        </AnimatePresence>

        {currentView === 'dashboard' ? (
          <DashboardView />
        ) : (
          <div className="app-container">
            <header className="header">
              <motion.h1
                initial={{ opacity: 0, y: -20 }}
                animate={{ opacity: 1, y: 0 }}
              >
                Psicólogo IA
              </motion.h1>
              <p className="status-text">Seu suporte profissional e preparação para terapia</p>
            </header>

            <motion.div
              className="main-card"
              layout
            >
              <section className="record-section">
                <button
                  className={`pulse-button ${gravando ? 'recording' : ''}`}
                  onClick={gravando ? pararGravacao : iniciarGravacao}
                  disabled={carregando}
                >
                  {gravando ? <Square size={48} /> : <Mic size={48} />}
                </button>
                <div className="status-container" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                  <span className="status-text">
                    {gravando ? 'Ouvindo desabafo...' : carregando ? 'Atualizando prontuário...' : exercicio ? 'Clique para dar seguimento' : 'Clique para começar a falar'}
                  </span>
                  {exercicio && !carregando && !gravando && (
                    <button className="reset-btn" onClick={() => { setTranscricao(''); setExercicio(''); setSessaoAtiva(null); window.speechSynthesis.cancel(); }}>
                      Novo Desabafo
                    </button>
                  )}
                </div>
              </section>

              <AnimatePresence mode="wait">
                {(transcricao || exercicio || carregando) && (
                  <motion.section
                    className="result-section"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                  >
                    <div className="result-card">
                      <h3><MessageSquare size={14} style={{ marginRight: 8 }} /> Seu Desabafo</h3>
                      <p>{carregando && !transcricao ? <span className="loading-dots">Transcrevendo áudio</span> : transcricao}</p>
                    </div>

                    {(exercicio || carregando) && (
                      <motion.div
                        className="result-card professional-card"
                        initial={{ opacity: 0, x: 20 }}
                        animate={{ opacity: 1, x: 0 }}
                      >
                        <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                          <h3 style={{ margin: 0, display: 'flex', alignItems: 'center' }}>
                            <Sparkles size={14} style={{ marginRight: 8 }} /> Análise e Preparação
                          </h3>
                          <div className="card-actions" style={{ display: 'flex', gap: '8px' }}>
                            {exercicio && (
                              <>
                                <button
                                  onClick={copiarParaPsicologo}
                                  className="audio-control-btn"
                                  title="Copiar Resumo para o Psicólogo"
                                  style={{ background: 'rgba(255,255,255,0.1)' }}
                                >
                                  <Calendar size={16} />
                                </button>
                                <button
                                  onClick={falando ? pararDeFalar : () => falar(exercicio)}
                                  className="audio-control-btn"
                                  title={falando ? "Parar áudio" : "Ouvir resposta"}
                                >
                                  {falando ? <Square size={16} fill="currentColor" /> : <Play size={16} fill="currentColor" />}
                                </button>
                              </>
                            )}
                          </div>
                        </div>
                        <div className="analysis-content">
                          {carregando && !exercicio ? (
                            <span className="loading-dots">Consultando abordagem terapêutica</span>
                          ) : (
                            formatarAnalise(exercicio)
                          )}
                        </div>
                      </motion.div>
                    )}
                  </motion.section>
                )}
              </AnimatePresence>
            </motion.div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
